import org.owasp.encoder.Encode;

import java.util.Scanner;

public class SafeXSSExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Sanitize user input to prevent XSS
        String safeName = Encode.forHtml(name);

        System.out.println("Hello, " + safeName + "!");

        // Simulate an attacker entering a malicious script as the input
        name = "<script>alert('XSS attack!')</script>";

        // Sanitize the malicious script input
        String safeMaliciousName = Encode.forHtml(name);

        System.out.println("Hello, " + safeMaliciousName + "!");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
